var topic = msg.topic;
var d = msg.payload;

// Stocke l'état de chaque source
if (topic === 'vigidrive/alertes') {
    var n = d.niveau || 0;
    if (n >= 3) global.set('cam_etat', 'DANGER');
    else if (n >= 2) global.set('cam_etat', 'FATIGUE');
    else if (n >= 1) global.set('cam_etat', 'WARNING');
    else global.set('cam_etat', 'NORMAL');
    global.set('cam_niveau', n);
    global.set('cam_perclos', d.PERCLOS || 0);
    global.set('cam_type', d.type || '');
}

if (topic === 'vigidrive/tilt') {
    var tn = d.niveau || 0;
    if (tn >= 3) global.set('mpu_etat', 'DANGER');
    else if (tn >= 2) global.set('mpu_etat', 'WARNING');
    else if (tn >= 1) global.set('mpu_etat', 'WARNING');
    else global.set('mpu_etat', 'NORMAL');
    global.set('mpu_niveau', tn);
    global.set('mpu_tilt', d.tilt || 0);
}

// Lecture états actuels
var cam = global.get('cam_etat') || 'NORMAL';
var mpu = global.get('mpu_etat') || 'NORMAL';
var cam_n = global.get('cam_niveau') || 0;
var mpu_n = global.get('mpu_niveau') || 0;

// TABLE DE FUSION
var niveau_final, etat_final, couleur;

if (cam === 'DANGER' && mpu === 'DANGER') {
    niveau_final = 4;
    etat_final   = 'CRITIQUE';
    couleur      = 'rouge_clignotant';
}
else if (cam === 'DANGER' || mpu === 'DANGER') {
    niveau_final = 3;
    etat_final   = 'DANGER';
    couleur      = 'rouge';
}
else if (cam === 'FATIGUE' || mpu === 'WARNING') {
    niveau_final = 2;
    etat_final   = 'FATIGUE';
    couleur      = 'orange';
}
else if (cam === 'WARNING' || mpu === 'WARNING') {
    niveau_final = 1;
    etat_final   = 'WARNING';
    couleur      = 'orange';
}
else {
    niveau_final = 0;
    etat_final   = 'NORMAL';
    couleur      = 'vert';
}

var commande = {
    niveau:   niveau_final,
    etat:     etat_final,
    couleur:  couleur,
    buzzer:   niveau_final >= 3,
    source:   'camera:' + cam + ' | mpu:' + mpu,
    perclos:  global.get('cam_perclos') || 0,
    tilt:     global.get('mpu_tilt') || 0,
    timestamp: new Date().toLocaleTimeString()
};

msg.payload = commande;
msg.topic   = 'vigidrive/commande';
return msg;

var d = msg.payload;
msg.payload = JSON.stringify({
    fusion_niveau: d.niveau,
    fusion_etat: d.etat,
    fusion_buzzer: d.buzzer ? 1 : 0,
    fusion_perclos: d.perclos,
    fusion_tilt: d.tilt
});
msg.topic = 'v1/devices/me/telemetry';
return msg;

var d = msg.payload;
function esc(s){ return String(s).replace(/'/g, "''"); }
var sql = "INSERT INTO historique (ts, niveau, etat, buzzer, perclos, tilt) VALUES (" +
    "datetime('now','localtime'), " +
    (Number(d.niveau)||0) + ", " +
    "'" + esc(d.etat||'') + "', " +
    (d.buzzer ? 1 : 0) + ", " +
    (Number(d.perclos)||0) + ", " +
    (Number(d.tilt)||0) + ")";
msg.topic = sql;
return msg;
